import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { catchError, Observable, of, shareReplay, tap } from 'rxjs';

export interface CategoryInfo {
  nome?: string;
  descrizione?: string;
  link?: string;
}

export interface SearchResult {
  id: string;
  nome: string;
  descrizione: string;
  link: string;
  score: number;
}

export interface TestQuestion {
  domanda?: string;
  se_si?: string;
  se_no?: string;
  categoria?: string;
}

export interface AppData {
  keywords: Record<string, string[]>;
  categorie: Record<string, CategoryInfo>;
  test_iniziale: TestQuestion[];
  regole: Record<string, string>;
  attivita: Record<string, unknown>;
}

@Injectable({ providedIn: 'root' })
export class DataService {
  private readonly endpoint =
    'https://script.google.com/macros/s/AKfycbyQlimUfoMV2SqQfvJtD1-msT5Q7RZyUDH1wZK-S9yqzGrxUZArkAh60IDOupf1eFmd/exec';
  private readonly cacheTtlMs = 300_000;
  private cacheTimestamp = 0;
  private cache: AppData = {
    keywords: {},
    categorie: {},
    test_iniziale: [],
    regole: {},
    attivita: {},
  };
  private data$?: Observable<AppData>;

  constructor(private http: HttpClient) {}

  loadData(force = false): Observable<AppData> {
    const cacheExpired = Date.now() - this.cacheTimestamp > this.cacheTtlMs;
    if (!this.data$ || force || cacheExpired) {
      this.data$ = this.http.get<AppData>(this.endpoint).pipe(
        tap((data) => {
          if (data) {
            this.cache = data;
            this.cacheTimestamp = Date.now();
          }
        }),
        catchError(() => {
          this.data$ = undefined;
          return of(this.cache);
        }),
        shareReplay({ bufferSize: 1, refCount: true })
      );
    }
    return this.data$;
  }

  getKeywordsList(): string[] {
    const merged = Object.values(this.cache.keywords || {}).flat();
    return Array.from(
      new Set(merged.filter(Boolean).map((item) => item.trim()))
    ).sort((a, b) => a.localeCompare(b, 'it'));
  }

  getAllCategories(): Record<string, CategoryInfo> {
    return this.cache.categorie || {};
  }

  getQuestions(categoryIds?: string[]): TestQuestion[] {
    let questions = [...(this.cache.test_iniziale || [])];
    if (categoryIds && categoryIds.length) {
      const normalizedIds = categoryIds.map((id) => id.toLowerCase());
      questions = questions.filter(
        (item) => item.categoria && normalizedIds.includes(item.categoria.toLowerCase())
      );
    }
    return questions;
  }

  findTop3Categories(queries: string[]): SearchResult[] {
    const scores: Record<string, number> = {};
    const keywords = this.cache.keywords || {};
    const categories = this.cache.categorie || {};

    queries.forEach((query) => {
      const q = query.trim().toLowerCase();
      if (!q) {
        return;
      }
      Object.entries(keywords).forEach(([category, words]) => {
        (words || []).forEach((word) => {
          const normalized = (word || '').toLowerCase();
          if (normalized.includes(q) || q.includes(normalized)) {
            scores[category] = (scores[category] || 0) + 1;
          }
        });
      });
    });

    return Object.keys(scores)
      .sort((a, b) => scores[b] - scores[a])
      .slice(0, 3)
      .map((category) => {
        const info = categories[category] || { nome: category, descrizione: '', link: '' };
        return {
          id: category,
          nome: info.nome || category,
          descrizione: info.descrizione || '',
          link: info.link || '',
          score: scores[category],
        };
      });
  }
}
